export interface ProcessingState {
  isProcessing: boolean;
  error: string | null;
  originalImage: string | null;
  processedImage: string | null;
}

export interface ImageFile {
  file: File;
  preview: string;
}

import { GoogleGenAI } from "@google/genai";
import { RETOUCH_PROMPT } from "../constants";

export const retouchImage = async (base64Image: string, mimeType: string): Promise<string> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing. Please ensure process.env.API_KEY is configured.");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Extract base64 data (strip prefix)
  const dataOnly = base64Image.split(",")[1];

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            data: dataOnly,
            mimeType: mimeType,
          },
        },
        {
          text: RETOUCH_PROMPT,
        },
      ],
    },
  });

  if (!response.candidates || response.candidates.length === 0) {
    throw new Error("No response generated from the model.");
  }

  // Iterate through parts to find the image data
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("The model did not return an image part in its response.");
};

import React, { useCallback } from 'react';

interface ImageUploaderProps {
  onImageSelect: (base64: string, mimeType: string) => void;
  disabled?: boolean;
}

const ImageUploader: React.FC<ImageUploaderProps> = ({ onImageSelect, disabled }) => {
  const handleFileChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onImageSelect(reader.result as string, file.type);
      };
      reader.readAsDataURL(file);
    }
  }, [onImageSelect]);

  return (
    <div className="w-full">
      <label className={`
        flex flex-col items-center justify-center w-full h-64 
        border-2 border-dashed rounded-2xl cursor-pointer
        transition-all duration-300
        ${disabled ? 'bg-gray-100 border-gray-300 cursor-not-allowed opacity-50' : 'bg-white border-indigo-300 hover:border-indigo-500 hover:bg-indigo-50/50'}
      `}>
        <div className="flex flex-col items-center justify-center pt-5 pb-6 px-4 text-center">
          <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mb-4">
            <i className="fa-solid fa-cloud-arrow-up text-indigo-600 text-2xl"></i>
          </div>
          <p className="mb-2 text-sm text-gray-700 font-semibold">
            Click to upload or drag and drop
          </p>
          <p className="text-xs text-gray-500">
            PNG, JPG, or WEBP (MAX. 10MB)
          </p>
        </div>
        <input 
          type="file" 
          className="hidden" 
          accept="image/*" 
          onChange={handleFileChange}
          disabled={disabled}
        />
      </label>
    </div>
  );
};

export default ImageUploader;

import React, { useState, useCallback } from 'react';
