    if (!state.originalImage) return;

    setState(prev => ({ ...prev, isProcessing: true, error: null }));

    try {
      const mimeType = state.originalImage.split(';')[0].split(':')[1];
      const result = await retouchImage(state.originalImage, mimeType);
      setState(prev => ({ ...prev, processedImage: result, isProcessing: false }));
    } catch (err) {
      console.error(err);
      setState(prev => ({ 
        ...prev, 
        isProcessing: false, 
        error: err instanceof Error ? err.message : "An unexpected error occurred while processing the image."
      }));
